public void testNestedBlocksWithDoLoop() {
    // Test nested blocks with DO loop
    assertPrint("if(x){{do{foo()}while(y);}}",
        "if(x){do foo();while(y)}");
}

public void testNestedBlocksWithFunction() {
    // Test nested blocks with FUNCTION
    assertPrint("if(x){{function foo(){}}}",
        "if(x){function foo(){}}");
}

public void testBlockWithMultipleStatementsAndDo() {
    // Block with multiple statements should keep braces
    assertPrint("if(x){var a=1;do{foo()}while(y)}",
        "if(x){var a=1;do foo();while(y)}");
}

public void testLabeledBlockWithDoLoop() {
    // Test labeled block containing DO loop
    assertPrint("if(x)A:{do{foo()}while(y)}",
        "if(x){A:do foo();while(y)}");
}
